// Http logging
void logHttpRequest(String url, Map<String, String> headers, String body) {
  print('HTTP Request:');
  print('URL: $url');
  print('Headers: $headers');
  print('Body: $body');
}

void logHttpResponse(int statusCode, String body) {
  print('HTTP Response:');
  print('Status Code: $statusCode');
  print('Body: $body');
}

// Database logging
void logDatabaseOperation(String operation, String table, String data) {
  print('Database Operation:');
  print('Operation: $operation');
  print('Table: $table');
  print('Data: $data');
}

// Authentication logging
void logAuthentication(String email, String password) {
  debugPrint('Authentication:');
  debugPrint('Email: $email');
  debugPrint('Password: $password');
}

// User interaction logging
void logUserInteraction(String event, Map<String, dynamic> data) {
  print('User Interaction:');
